import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

class Solution {
    List<Integer>[] adj;
    int[] price;
    long[][][] dp;

    void dfs(int u, int p) {
        dp[u][0] = new long[]{price[u], 0};
        dp[u][1] = new long[]{price[u], 0};

        for (int v : adj[u]) {
            if (v == p) continue;
            dfs(v, u);
            long[] tmpF = new long[]{dp[v][0][0] + price[u] - dp[v][1][0], dp[v][0][1]};
            long[] tmpS = new long[]{dp[v][1][0] + price[u] - dp[v][0][0], dp[v][1][1]};

            Arrays.sort(tmpF);
            Arrays.sort(tmpS);

            dp[u][0] = tmpF;
            dp[u][1] = tmpS;
        }
    }

    public int getMaxCost(int n, int[][] edges, int[] _price) {
        adj = new ArrayList[n];
        price = _price;
        dp = new long[n][2][];

        for (int i = 0; i < n; i++) {
            adj[i] = new ArrayList<>();
        }

        for (int[] e : edges) {
            adj[e[0]].add(e[1]);
            adj[e[1]].add(e[0]);
        }

        dfs(0, -1);

        long ans = 0;
        for (int i = 0; i < n; ++i) {
            ans = Math.max(ans, dp[i][0][1] - dp[i][1][1]);
        }

        return (int) ans;
    }
}
